/** @type {import('prettier').Config & import('prettier-plugin-tailwindcss').PluginOptions} */
export default {
  plugins: ["prettier-plugin-tailwindcss"],
};

"use client";

import { use } from "react";
import { motion } from "framer-motion";
import { Heart, MessageCircle, ArrowLeft } from "lucide-react";
import Link from "next/link";
import { formatDistanceToNow } from "date-fns";
import { api } from "~/trpc/react";
import { Avatar } from "~/components/ui/avatar";

type Props = {
  params: Promise<{
    username: string;
  }>;
};

export default function LikesPage({ params }: Props) {
  const { username } = use(params);

  const { data: user } = api.user.getByUsername.useQuery({ username });
  const { data: videos } = api.user.getLikesBreakdown.useQuery(
    { userId: user?.id ?? "" },
    { enabled: !!user?.id }
  );

  const totalLikes = videos?.reduce((acc, video) => acc + video._count.likes, 0) ?? 0;

  return (
    <main className="min-h-screen bg-[#0a0a0a] pb-20 text-white md:pb-0">
      <div className="mx-auto max-w-5xl px-4 py-8">
        {/* Header */}
        <div className="mb-8">
          <Link
            href={`/${username}`}
            className="mb-4 inline-flex items-center gap-2 text-sm text-gray-400 hover:text-white"
          >
            <ArrowLeft className="h-4 w-4" />
            Back to profile
          </Link>
          <div className="flex items-center gap-4">
            <div className="flex h-16 w-16 items-center justify-center rounded-full bg-gradient-to-br from-pink-500 to-cyan-400">
              <Heart className="h-8 w-8 text-white" />
            </div>
            <div>
              <h1 className="mb-1 text-3xl font-bold">Likes Breakdown</h1>
              <p className="text-gray-400">
                {totalLikes.toLocaleString()} total likes across {videos?.length ?? 0} videos
              </p>
            </div>
          </div>
        </div>

        {/* Videos List */}
        {!videos || videos.length === 0 ? (
          <div className="rounded-2xl border border-white/10 bg-white/5 p-12 text-center">
            <div className="mx-auto mb-4 flex h-20 w-20 items-center justify-center rounded-full bg-white/5">
              <Heart className="h-10 w-10 text-gray-400" />
            </div>
            <h3 className="mb-2 text-xl font-semibold">No videos yet</h3>
            <p className="text-gray-400">Upload videos to see likes breakdown</p>
          </div>
        ) : (
          <div className="space-y-6">
            {videos.map((video, index) => (
              <motion.div
                key={video.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.05 }}
                className="rounded-2xl border border-white/10 bg-white/5 p-6"
              >
                <div className="mb-4 flex items-start gap-4">
                  {/* Video Thumbnail */}
                  <Link href={`/?videoId=${video.id}`}>
                    <div className="h-32 w-24 flex-shrink-0 overflow-hidden rounded-lg bg-white/5">
                      <video
                        src={video.filePath}
                        className="h-full w-full object-cover"
                        muted
                      />
                    </div>
                  </Link>

                  {/* Video Info */}
                  <div className="flex-1">
                    <Link href={`/?videoId=${video.id}`}>
                      <h3 className="mb-2 text-lg font-semibold hover:underline">
                        {video.title || "Untitled Video"}
                      </h3>
                    </Link>
                    <div className="flex items-center gap-4 text-sm text-gray-400">
                      <div className="flex items-center gap-1">
                        <Heart className="h-4 w-4 text-[#FE2C55]" />
                        <span>{video._count.likes.toLocaleString()} likes</span>
                      </div>
                      <div className="flex items-center gap-1">
                        <MessageCircle className="h-4 w-4 text-cyan-400" />
                        <span>{video._count.comments.toLocaleString()} comments</span>
                      </div>
                      <span>
                        {formatDistanceToNow(new Date(video.createdAt), { addSuffix: true })}
                      </span>
                    </div>
                  </div>

                  {/* Like Percentage */}
                  <div className="text-right">
                    <div className="mb-1 text-2xl font-bold text-pink-500">
                      {totalLikes > 0
                        ? Math.round((video._count.likes / totalLikes) * 100)
                        : 0}
                      %
                    </div>
                    <div className="text-xs text-gray-400">of total likes</div>
                  </div>
                </div>

                {/* Recent Likers */}
                {video.likes.length > 0 && (
                  <div className="border-t border-white/10 pt-4">
                    <h4 className="mb-3 text-sm font-medium text-gray-400">Recent likes</h4>
                    <div className="flex flex-wrap gap-3">
                      {video.likes.map((like) => (
                        <Link
                          key={like.user.id}
                          href={`/${like.user.username ?? like.user.name}`}
                          className="group flex items-center gap-2 rounded-lg border border-white/10 bg-white/5 px-3 py-2 transition-all hover:border-white/20"
                        >
                          <Avatar
                            src={like.user.image ?? undefined}
                            fallback={
                              like.user.username?.charAt(0).toUpperCase() ??
                              like.user.name?.charAt(0).toUpperCase() ??
                              "U"
                            }
                            size="sm"
                          />
                          <span className="text-sm group-hover:underline">
                            {like.user.name ?? like.user.username}
                          </span>
                        </Link>
                      ))}
                      {video._count.likes > 10 && (
                        <div className="flex items-center rounded-lg border border-white/10 bg-white/5 px-3 py-2 text-sm text-gray-400">
                          +{video._count.likes - 10} more
                        </div>
                      )}
                    </div>
                  </div>
                )}
              </motion.div>
            ))}
          </div>
        )}
      </div>
    </main>
  );
}

"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import { Settings, Share2, MoreHorizontal, Grid, Heart, Bookmark, Lock } from "lucide-react";
import Link from "next/link";
import { useSession } from "next-auth/react";
import toast from "react-hot-toast";
import { api } from "~/trpc/react";
import { Button } from "~/components/ui/button";
import { Avatar } from "~/components/ui/avatar";

export interface UserProfileProps {
  user: {
    name: string | null;
    id: string;
    createdAt: Date;
    username: string | null;
    image: string | null;
    videos?: { 
      id: number; 
      title: string | null; 
      filePath: string; 
      createdAt: Date; 
      _count: { comments?: number; likes: number; }; 
    }[];
    _count?: { followers?: number; following?: number; videos?: number; };
    bio?: string | null;
  };
}

export default function UserProfile({ user }: UserProfileProps) {
  const { data: session } = useSession();
  const [activeTab, setActiveTab] = useState<'videos' | 'liked' | 'saved'>('videos');
  const isOwnProfile = session?.user?.id === user.id;
  const utils = api.useUtils();

  // Check if following
  const { data: followStatus } = api.follow.isFollowing.useQuery(
    { userId: user.id },
    { enabled: !isOwnProfile }
  );

  // Optimistic local follow state
  const [optimisticFollowing, setOptimisticFollowing] = useState<boolean | null>(null);
  const [optimisticFollowerCount, setOptimisticFollowerCount] = useState(
    user._count?.followers ?? 0
  );

  // Derived follow status: prefer optimistic state, fall back to server
  const isFollowing = optimisticFollowing ?? followStatus?.following ?? false;

  // Follow mutation with optimistic UI
  const toggleFollowMutation = api.follow.toggleFollow.useMutation({
    onMutate: () => {
      const wasFollowing = isFollowing;
      setOptimisticFollowing(!wasFollowing);
      setOptimisticFollowerCount((prev) => prev + (wasFollowing ? -1 : 1));
    },
    onSuccess: () => {
      void utils.follow.isFollowing.invalidate();
      void utils.user.getByUsername.invalidate();
      toast.success(isFollowing ? "Unfollowed" : "Following!");
    },
    onError: (error) => {
      // Roll back on error
      setOptimisticFollowing(followStatus?.following ?? false);
      setOptimisticFollowerCount(user._count?.followers ?? 0);
      toast.error(error.message);
    },
  });

  // Message mutation
  const sendMessageMutation = api.message.sendMessage.useMutation({
    onSuccess: (data) => {
      // Navigate to messages page with conversation
      window.location.href = `/messages?conversationId=${data.conversationId ?? ''}`;
    },
    onError: (error) => {
      toast.error(error.message);
    },
  });

  const handleFollow = () => {
    if (!session) {
      toast.error("Please sign in to follow users");
      return;
    }
    toggleFollowMutation.mutate({ userId: user.id });
  };

  const handleMessage = () => {
    if (!session) {
      toast.error("Please sign in to send messages");
      return;
    }
    // Navigate to messages with recipient ID
    window.location.href = `/messages?recipientId=${user.id}`;
  };

  const handleShare = async () => {
    const profileUrl = `${window.location.origin}/${user.username ?? user.name}`;
    const shareData = {
      title: `${user.name ?? user.username}'s Profile`,
      text: `Check out @${user.username ?? user.name} on bip bop!`,
      url: profileUrl,
    };

    // Check if Web Share API is supported
    if (navigator.share) {
      try {
        await navigator.share(shareData);
        toast.success('Profile shared successfully!');
      } catch (err) {
        // User cancelled or error occurred
        if ((err as Error).name !== 'AbortError') {
          // Fallback to clipboard
          await navigator.clipboard.writeText(profileUrl);
          toast.success('Profile link copied to clipboard!');
        }
      }
    } else {
      // Fallback to clipboard
      await navigator.clipboard.writeText(profileUrl);
      toast.success('Profile link copied to clipboard!');
    }
  };

  // Fetch liked videos (no args ΓÇö server derives userId from session)
  const { data: likedVideos } = api.video.getLikedVideos.useQuery(
    undefined,
    { enabled: activeTab === 'liked' && isOwnProfile }
  );

  // Fetch saved videos (no args ΓÇö server derives userId from session)
  const { data: savedVideos } = api.video.getSavedVideos.useQuery(
    undefined,
    { enabled: activeTab === 'saved' && isOwnProfile }
  );

  const stats = [
    { label: 'Following', value: user._count?.following ?? 0 },
    { label: 'Followers', value: optimisticFollowerCount },
    { label: 'Likes', value: user.videos?.reduce((acc, v) => acc + v._count.likes, 0) ?? 0 },
  ];

  const tabs = [
    { id: 'videos', label: 'Videos', icon: Grid },
    { id: 'liked', label: 'Liked', icon: Heart },
    { id: 'saved', label: 'Saved', icon: Bookmark },
  ];

  return (
    <main className="min-h-screen bg-[#0a0a0a] text-white pb-20 md:pb-0">
      <div className="max-w-5xl mx-auto px-4 py-8">
        {/* Profile Header */}
        <div className="mb-8">
          <div className="flex flex-col md:flex-row items-center md:items-start gap-6 mb-6">
            {/* Avatar */}
            <motion.div
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{ duration: 0.3 }}
            >
              <Avatar
                src={user.image ?? undefined}
                fallback={user.username?.charAt(0).toUpperCase() ?? user.name?.charAt(0).toUpperCase() ?? 'U'}
                size="xl"
                className="ring-4 ring-[#7c3aed] shadow-[0_0_20px_rgba(124,58,237,0.6)]"
              />
            </motion.div>

            {/* Info */}
            <div className="flex-1 text-center md:text-left">
              <div className="flex flex-col md:flex-row items-center md:items-start gap-4 mb-4">
                <div>
                  <h1 className="text-3xl font-bold mb-1 text-transparent bg-clip-text bg-gradient-to-r from-pink-500 to-purple-500">
                    {user.name ?? user.username ?? 'User'}
                  </h1>
                  <p className="text-gray-400">@{user.username ?? 'username'}</p>
                </div>

                <div className="flex items-center gap-2">
                  {isOwnProfile ? (
                    <>
                      <Link href="/settings">
                        <Button variant="secondary" size="md">
                          <Settings className="w-4 h-4 mr-2" />
                          Edit Profile
                        </Button>
                      </Link>
                      <Button variant="secondary" size="md" onClick={handleShare}>
                        <Share2 className="w-4 h-4" />
                      </Button>
                    </>
                  ) : (
                    <>
                      <Button 
                        variant={isFollowing ? "secondary" : "primary"} 
                        size="md"
                        onClick={handleFollow}
                        isLoading={toggleFollowMutation.isPending}
                      >
                        {isFollowing ? "Following" : "Follow"}
                      </Button>
                      <Button 
                        variant="secondary" 
                        size="md"
                        onClick={handleMessage}
                      >
                        Message
                      </Button>
                      <Button variant="secondary" size="md" onClick={handleShare}>
                        <Share2 className="w-4 h-4" />
                      </Button>
                      <Button variant="secondary" size="md">
                        <MoreHorizontal className="w-4 h-4" />
                      </Button>
                    </>
                  )}
                </div>
              </div>

              {/* Stats */}
              <div className="flex items-center justify-center md:justify-start gap-6 mb-4">
                <Link href={`/${user.username ?? user.name}/followers`}>
                  <button className="flex flex-col items-center hover:opacity-80 transition-opacity">
                    <span className="text-xl font-bold">{stats[0]?.value.toLocaleString()}</span>
                    <span className="text-sm text-gray-400">{stats[0]?.label}</span>
                  </button>
                </Link>
                <Link href={`/${user.username ?? user.name}/followers`}>
                  <button className="flex flex-col items-center hover:opacity-80 transition-opacity">
                    <span className="text-xl font-bold">{stats[1]?.value.toLocaleString()}</span>
                    <span className="text-sm text-gray-400">{stats[1]?.label}</span>
                  </button>
                </Link>
                <Link href={`/${user.username ?? user.name}/likes`}>
                  <button className="flex flex-col items-center hover:opacity-80 transition-opacity">
                    <span className="text-xl font-bold">{stats[2]?.value.toLocaleString()}</span>
                    <span className="text-sm text-gray-400">{stats[2]?.label}</span>
                  </button>
                </Link>
              </div>

              {/* Bio */}
              {user.bio && (
                <p className="text-gray-300 mb-4 max-w-md">
                  {user.bio}
                </p>
              )}
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="border-b border-white/10 mb-6">
          <div className="flex items-center justify-center gap-2">
            {tabs.map((tab) => {
              const Icon = tab.icon;
              const isActive = activeTab === tab.id;
              
              return (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id as typeof activeTab)}
                  className={`relative flex items-center gap-2 px-6 py-3 transition-colors ${
                    isActive ? 'text-white' : 'text-gray-400 hover:text-white'
                  }`}
                >
                  <Icon className="w-5 h-5" />
                  <span className="font-medium">{tab.label}</span>
                  
                  {isActive && (
                    <motion.div
                      layoutId="activeProfileTab"
                      className="absolute bottom-0 left-0 right-0 h-0.5 bg-gradient-to-r from-pink-500 to-cyan-400"
                      transition={{ type: "spring", stiffness: 380, damping: 30 }}
                    />
                  )}
                </button>
              );
            })}
          </div>
        </div>

        {/* Content */}
        <div>
          {activeTab === 'videos' && (
            <div>
              {user.videos && user.videos.length > 0 ? (
                <div className="grid grid-cols-3 gap-1">
                  {user.videos.map((video) => (
                    <Link key={video.id} href={`/?videoId=${video.id}`}>
                      <motion.div
                        whileHover={{ scale: 1.02 }}
                        className="relative aspect-[9/16] bg-white/5 rounded-lg overflow-hidden cursor-pointer group"
                      >
                        <video
                          src={video.filePath}
                          className="w-full h-full object-cover"
                          muted
                          playsInline
                          onMouseEnter={(e) => e.currentTarget.play()}
                          onMouseLeave={(e) => {
                            e.currentTarget.pause();
                            e.currentTarget.currentTime = 0;
                          }}
                        />
                        <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                          <div className="text-center">
                            <Heart className="w-6 h-6 mx-auto mb-1" />
                            <span className="text-sm font-semibold">
                              {video._count.likes.toLocaleString()}
                            </span>
                          </div>
                        </div>
                      </motion.div>
                    </Link>
                  ))}
                </div>
              ) : (
                <EmptyState
                  icon={Grid}
                  title="No videos yet"
                  description="Videos you upload will appear here"
                />
              )}
            </div>
          )}

          {activeTab === 'liked' && (
            <div>
              {!isOwnProfile ? (
                <EmptyState
                  icon={Lock}
                  title="Private content"
                  description="Liked videos are private"
                  isPrivate
                />
              ) : likedVideos?.items && likedVideos.items.length > 0 ? (
                <div className="grid grid-cols-3 gap-1">
                  {likedVideos.items.map((video) => (
                    <Link key={video.id} href={`/?videoId=${video.id}`}>
                      <motion.div
                        whileHover={{ scale: 1.02 }}
                        className="relative aspect-[9/16] bg-white/5 rounded-lg overflow-hidden cursor-pointer group"
                      >
                        <video
                          src={video.filePath}
                          className="w-full h-full object-cover"
                          muted
                          playsInline
                          onMouseEnter={(e) => e.currentTarget.play()}
                          onMouseLeave={(e) => {
                            e.currentTarget.pause();
                            e.currentTarget.currentTime = 0;
                          }}
                        />
                        <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                          <div className="text-center">
                            <Heart className="w-6 h-6 mx-auto mb-1 fill-[#FE2C55] text-[#FE2C55]" />
                            <span className="text-sm font-semibold">
                              {video._count.likes.toLocaleString()}
                            </span>
                          </div>
                        </div>
                      </motion.div>
                    </Link>
                  ))}
                </div>
              ) : (
                <EmptyState
                  icon={Heart}
                  title="No liked videos"
                  description="Videos you like will appear here"
                />
              )}
            </div>
          )}

          {activeTab === 'saved' && (
            <div>
              {!isOwnProfile ? (
                <EmptyState
                  icon={Lock}
                  title="Private content"
                  description="Saved videos are private"
                  isPrivate
                />
              ) : savedVideos?.items && savedVideos.items.length > 0 ? (
                <div className="grid grid-cols-3 gap-1">
                  {savedVideos.items.map((video) => (
                    <Link key={video.id} href={`/?videoId=${video.id}`}>
                      <motion.div
                        whileHover={{ scale: 1.02 }}
                        className="relative aspect-[9/16] bg-white/5 rounded-lg overflow-hidden cursor-pointer group"
                      >
                        <video
                          src={video.filePath}
                          className="w-full h-full object-cover"
                          muted
                          playsInline
                          onMouseEnter={(e) => e.currentTarget.play()}
                          onMouseLeave={(e) => {
                            e.currentTarget.pause();
                            e.currentTarget.currentTime = 0;
                          }}
                        />
                        <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                          <div className="text-center">
                            <Bookmark className="w-6 h-6 mx-auto mb-1 fill-yellow-500 text-yellow-500" />
                            <span className="text-sm font-semibold">
                              {video._count.likes.toLocaleString()}
                            </span>
                          </div>
                        </div>
                      </motion.div>
                    </Link>
                  ))}
                </div>
              ) : (
                <EmptyState
                  icon={Bookmark}
                  title="No saved videos"
                  description="Videos you save will appear here"
                />
              )}
            </div>
          )}
        </div>
      </div>
    </main>
  );
}

function EmptyState({
  icon: Icon,
  title,
  description,
  isPrivate = false,
}: {
  icon: React.ComponentType<{ className?: string }>;
  title: string;
  description: string;
  isPrivate?: boolean;
}) {
  return (
    <div className="text-center py-16">
      <div className="w-20 h-20 mx-auto mb-4 rounded-full bg-white/5 flex items-center justify-center">
        {isPrivate ? (
          <Lock className="w-10 h-10 text-gray-400" />
        ) : (
          <Icon className="w-10 h-10 text-gray-400" />
        )}
      </div>
      <h3 className="text-xl font-semibold mb-2">{title}</h3>
      <p className="text-gray-400">{description}</p>
      {isPrivate && (
        <p className="text-sm text-gray-500 mt-2">This content is private</p>
      )}
    </div>
  );
}

"use client";

import { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import Comments from './comments';
import { api } from "~/trpc/react";
import { useSession } from "next-auth/react";
import toast from "react-hot-toast";
import { Heart, MessageCircle, Share2, Bookmark, Volume2, VolumeX, Play, Eye } from "lucide-react";
import { cn, formatNumber } from "~/lib/utils";
import { Avatar } from "~/components/ui/avatar";
import { Button } from "~/components/ui/button";
import VideoOptionsMenu from "./video-options-menu";
import ShinyText from "~/components/ui/shiny-text";

interface VideoCardProps {
  id: number;
  videoUrl: string;
  thumbnailUrl?: string;
  username: string;
  userId: string;
  description: string;
  likesCount?: number;
  commentsCount?: number;
  viewsCount?: number;
  isLiked?: boolean;
  isBookmarked?: boolean;
  isActive?: boolean;
}

export default function VideoCard({
  id,
  videoUrl,
  thumbnailUrl,
  username,
  userId,
  description,
  likesCount = 0,
  commentsCount = 0,
  viewsCount = 0,
  isLiked = false,
  isBookmarked = false,
  isActive = false,
}: VideoCardProps) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const { data: session } = useSession();
  const [liked, setLiked] = useState(isLiked);
  const [likes, setLikes] = useState(likesCount);
  const [bookmarked, setBookmarked] = useState(isBookmarked);
  const [comments, setComments] = useState(commentsCount);
  const [views, setViews] = useState(viewsCount);
  const [following, setFollowing] = useState(false);
  const viewRecordedRef = useRef(false);
  const [showComments, setShowComments] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isMuted, setIsMuted] = useState(true);

  const toggleLikeMutation = api.video.toggleLike.useMutation({
    onSuccess: (data) => {
      setLiked(data.liked);
      setLikes(prev => data.liked ? prev + 1 : prev - 1);
    },
    onError: (error) => {
      toast.error(`Error: ${error.message}`);
    }
  });

  const toggleBookmarkMutation = api.video.toggleBookmark.useMutation({
    onSuccess: (data) => {
      setBookmarked(data.bookmarked);
      toast.success(data.bookmarked ? "Video saved!" : "Video removed from saved");
    },
    onError: (error) => {
      toast.error(`Error: ${error.message}`);
    }
  });

  const toggleFollowMutation = api.follow.toggleFollow.useMutation({
    onSuccess: (data) => {
      setFollowing(data.following);
      toast.success(data.following ? `Following @${username}` : `Unfollowed @${username}`);
    },
    onError: (error) => {
      toast.error(`Error: ${error.message}`);
    }
  });

  const recordViewMutation = api.video.recordView.useMutation({
    onSuccess: () => setViews(v => v + 1),
  });

  // Check if following
  const { data: followData } = api.follow.isFollowing.useQuery(
    { userId },
    { enabled: !!session && userId !== session.user.id }
  );

  useEffect(() => {
    if (followData) {
      setFollowing(followData.following);
    }
  }, [followData]);

  // Handle video playback based on active state
  useEffect(() => {
    if (videoRef.current) {
      if (isActive) {
        videoRef.current.play().catch(() => console.error("Video play error"));
        setIsPlaying(true);

        // Record view after 2s of active playback (prevents swipe-through inflation)
        const timer = setTimeout(() => {
          if (!viewRecordedRef.current) {
            viewRecordedRef.current = true;
            recordViewMutation.mutate({ videoId: id });
          }
        }, 2000);

        return () => clearTimeout(timer);
      } else {
        videoRef.current.pause();
        setIsPlaying(false);
        viewRecordedRef.current = false; // reset so re-watch counts again
      }
    }
  }, [isActive, id]);



  const handleShare = async () => {
    if (navigator.share) {
      await navigator.share({
        title: 'Check out this video on bip bop!',
        url: window.location.href,
      });
    } else {
      await navigator.clipboard.writeText(window.location.href);
      toast.success('Link copied to clipboard!');
    }
  };

  const handleLike = () => {
    if (!session) {
      toast.error("You must be signed in to like videos");
      return;
    }
    toggleLikeMutation.mutate({ videoId: id });
  };

  const handleComment = () => {
    if (!session) {
      toast.error("You must be signed in to comment");
      return;
    }
    setShowComments(!showComments);
  };

  const handleBookmark = () => {
    if (!session) {
      toast.error("You must be signed in to save videos");
      return;
    }
    toggleBookmarkMutation.mutate({ videoId: id });
  };

  const handleFollow = () => {
    if (!session) {
      toast.error("You must be signed in to follow users");
      return;
    }
    if (userId === session.user.id) {
      toast.error("You cannot follow yourself");
      return;
    }
    toggleFollowMutation.mutate({ userId });
  };

  // Double tap to like
  const [lastTap, setLastTap] = useState(0);
  const handleDoubleTap = () => {
    const now = Date.now();
    if (now - lastTap < 300) { // 300ms between taps
      if (!liked) {
        handleLike();
      }
    }
    setLastTap(now);
  };

  return (
    <div className="relative h-full w-full bg-black overflow-hidden">
      {/* Video */}
      <div className="absolute inset-0 z-0">
        <video
          ref={videoRef}
          src={videoUrl}
          poster={thumbnailUrl}
          className="h-full w-full object-cover"
          loop
          playsInline
          muted={isMuted}
          onClick={handleDoubleTap}
        />

        {/* Double tap heart animation */}
        <AnimatePresence>
          {!isPlaying && (
            <motion.div
              initial={{ scale: 0, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0, opacity: 0 }}
              className="absolute inset-0 flex items-center justify-center pointer-events-none"
            >
              <motion.div
                animate={{ scale: [1, 1.2, 1] }}
                transition={{ duration: 0.6, repeat: Infinity }}
                className="rounded-full bg-black/30 backdrop-blur-sm p-6"
              >
                <Play className="h-16 w-16 text-white fill-white" />
              </motion.div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      {/* Top gradient overlay */}
      <div className="absolute top-0 left-0 right-0 h-32 bg-gradient-to-b from-black/60 to-transparent z-10 pointer-events-none" />

      {/* Full screen gradient overlay for consistent contrast */}
      <div className="absolute inset-0 bg-gradient-to-b from-black/10 via-transparent to-black/80 z-10 pointer-events-none" />

      {/* User info and description */}
      <div className="absolute bottom-20 left-4 right-20 z-20 text-white">
        <div className="flex items-center gap-3 mb-3">
          <motion.div 
            whileHover={{ scale: 1.1 }}
            className="rounded-full border-2 border-[#7c3aed] shadow-[0_0_10px_rgba(124,58,237,0.5)] p-[2px]"
          >
            <Avatar
              fallback={username.charAt(0).toUpperCase()}
              size="lg"
            />
          </motion.div>
          <div className="flex-1">
            <ShinyText text={`@${username}`} className="text-lg font-bold drop-shadow-md" speed={3} />
          </div>
          {session && userId !== session.user.id && (
            <Button
              variant={following ? "secondary" : "primary"}
              size="sm"
              onClick={handleFollow}
              disabled={toggleFollowMutation.isPending}
              className="px-3 py-1 rounded-full bg-transparent border border-white/30 text-white text-xs font-semibold backdrop-blur-md hover:bg-white/10"
            >
              {following ? "Following" : "Follow"}
            </Button>
          )}
        </div>

        {description && (
          <p className="text-sm leading-relaxed mb-3 drop-shadow-md line-clamp-2">{description}</p>
        )}

        <div className="flex items-center gap-2 mt-3 bg-white/10 w-fit px-3 py-1.5 rounded-full backdrop-blur-md border border-white/20 shadow-[0_4px_30px_rgba(0,0,0,0.1)]">
          <span className="text-white text-xs opacity-80 animate-bounce">ΓÖ½</span>
          <ShinyText text={`Original sound - ${username}`} className="text-xs font-medium truncate w-48 drop-shadow-md" />
        </div>
      </div>

      {/* Action buttons sidebar */}
      <div className="absolute right-3 bottom-24 z-20 flex flex-col gap-6">
        {/* Like button */}
        <motion.button
          whileTap={{ scale: 0.9 }}
          onClick={handleLike}
          disabled={toggleLikeMutation.isPending}
          className="flex flex-col items-center gap-1 group"
        >
          <motion.div
            animate={liked ? { scale: [1, 1.3, 1] } : {}}
            transition={{ duration: 0.3 }}
            className="relative"
          >
            <div className={cn(
              "flex items-center justify-center rounded-full p-3 backdrop-blur-md border shadow-[0_4px_30px_rgba(0,0,0,0.1)] transition-all",
              liked ? "bg-[#ec4899]/20 border-[#ec4899]/50 shadow-[0_0_15px_rgba(236,72,153,0.3)]" : "bg-white/10 border-white/20 group-hover:bg-white/20 group-hover:border-white/40"
            )}>
              <Heart
                className={cn(
                  "h-7 w-7 transition-all",
                  liked ? "fill-[#ec4899] text-[#ec4899]" : "text-white"
                )}
              />
            </div>
          </motion.div>
          <span className="text-white text-xs font-bold drop-shadow-md">
            {formatNumber(likes)}
          </span>
        </motion.button>

        {/* Comment button */}
        <motion.button
          whileTap={{ scale: 0.9 }}
          onClick={handleComment}
          className="flex flex-col items-center gap-1 group"
        >
          <div className="flex items-center justify-center rounded-full p-3 bg-white/10 backdrop-blur-md border border-white/20 shadow-[0_4px_30px_rgba(0,0,0,0.1)] group-hover:bg-white/20 group-hover:border-white/40 transition-all">
            <MessageCircle className="h-7 w-7 text-white" />
          </div>
          <span className="text-white text-xs font-bold drop-shadow-md">
            {formatNumber(comments)}
          </span>
        </motion.button>

        {/* Views */}
        <div className="flex flex-col items-center gap-1 group">
          <div className="flex items-center justify-center rounded-full p-3 bg-white/10 backdrop-blur-md border border-white/20 shadow-[0_4px_30px_rgba(0,0,0,0.1)] group-hover:bg-white/20 group-hover:border-white/40 transition-all">
            <Eye className="h-7 w-7 text-white" />
          </div>
          <span className="text-white text-xs font-bold drop-shadow-md">
            {formatNumber(views)}
          </span>
        </div>

        {/* Bookmark button */}
        <motion.button
          whileTap={{ scale: 0.9 }}
          onClick={handleBookmark}
          disabled={toggleBookmarkMutation.isPending}
          className="flex flex-col items-center gap-1 group"
        >
          <motion.div
            animate={bookmarked ? { scale: [1, 1.3, 1] } : {}}
            transition={{ duration: 0.3 }}
          >
            <div className={cn(
              "flex items-center justify-center rounded-full p-3 backdrop-blur-md border shadow-[0_4px_30px_rgba(0,0,0,0.1)] transition-all",
              bookmarked ? "bg-yellow-500/20 border-yellow-500/50 shadow-[0_0_15px_rgba(234,179,8,0.3)]" : "bg-white/10 border-white/20 group-hover:bg-white/20 group-hover:border-white/40"
            )}>
              <Bookmark
                className={cn(
                  "h-7 w-7 transition-all",
                  bookmarked ? "fill-yellow-500 text-yellow-500" : "text-white"
                )}
              />
            </div>
          </motion.div>
        </motion.button>

        {/* Share button */}
        <motion.button
          whileTap={{ scale: 0.9 }}
          onClick={handleShare}
          className="flex flex-col items-center gap-1 group"
        >
          <div className="flex items-center justify-center rounded-full p-3 bg-white/10 backdrop-blur-md border border-white/20 shadow-[0_4px_30px_rgba(0,0,0,0.1)] group-hover:bg-white/20 group-hover:border-white/40 transition-all">
            <Share2 className="h-7 w-7 text-white" />
          </div>
        </motion.button>

        {/* More options */}
        <VideoOptionsMenu
          videoId={id}
          videoUrl={videoUrl}
          userId={userId}
          username={username}
        />

        {/* Rotating disc avatar */}
        <motion.div
          animate={{ rotate: isPlaying ? 360 : 0 }}
          transition={{ duration: 3, repeat: isPlaying ? Infinity : 0, ease: "linear" }}
          className="mt-2"
        >
          <Avatar
            fallback={username.charAt(0).toUpperCase()}
            size="lg"
          />
        </motion.div>
      </div>

      {/* Volume control */}
      <motion.button
        whileTap={{ scale: 0.9 }}
        onClick={() => setIsMuted(m => !m)}
        className="absolute top-4 right-4 z-20 p-2 rounded-full bg-black/30 backdrop-blur-sm"
      >
        {isMuted ? (
          <VolumeX className="h-5 w-5 text-white" />
        ) : (
          <Volume2 className="h-5 w-5 text-white" />
        )}
      </motion.button>

      {/* Comments drawer */}
      <AnimatePresence>
        {showComments && (
          <motion.div
            initial={{ y: "100%" }}
            animate={{ y: 0 }}
            exit={{ y: "100%" }}
            transition={{ type: "spring", damping: 30, stiffness: 300 }}
            className="absolute inset-0 z-30 bg-black/95 backdrop-blur-xl"
          >
            <div className="h-full flex flex-col">
              <div className="flex items-center justify-between p-4 border-b border-white/10">
                <h3 className="text-white font-semibold text-lg">Comments</h3>
                <button
                  type="button"
                  onClick={() => setShowComments(false)}
                  className="text-white/70 hover:text-white transition-colors"
                  aria-label="Close comments"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
              </div>
              <div className="flex-1 overflow-y-auto">
                <Comments
                  videoId={id}
                  onCommentAdded={() => setComments(prev => prev + 1)}
                />
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

"use client";

import { useState, useRef, useEffect } from "react";
import { motion } from "framer-motion";
import {
  Play,
  Pause,
  Volume2,
  VolumeX,
  Scissors,
  Type,
  Music,
  Sparkles,
  Palette,
  ArrowLeft,
  ArrowRight,
  Sliders,
  Filter,
} from "lucide-react";
import { Input } from "~/components/ui/input";
import { Button } from "~/components/ui/button";
import { api } from "~/trpc/react";
import { useRouter } from "next/navigation";
import toast from "react-hot-toast";

interface VideoEditorProps {
  videoFile: File;
  onBack: () => void;
  onNext: () => void;
}

export default function VideoEditor({
  videoFile,
  onBack,
  onNext,
}: VideoEditorProps) {
  const router = useRouter();
  const videoRef = useRef<HTMLVideoElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [videoUrl, setVideoUrl] = useState<string>("");
  const [isUploading, setIsUploading] = useState(false);

  // Editor states
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [selectedTab, setSelectedTab] = useState<
    "text" | "music" | "effects" | "filters"
  >("text");

  // API mutation
  const createVideoMutation = api.video.create.useMutation({
    onSuccess: () => {
      toast.success("Video published successfully!");
      onNext();
      router.push("/");
    },
    onError: (error) => {
      toast.error(`Failed to publish: ${error.message}`);
      setIsUploading(false);
    },
  });

  // Text overlay
  const [textOverlay, setTextOverlay] = useState("");
  const [textColor, setTextColor] = useState("#ffffff");
  const [textPosition, setTextPosition] = useState<"top" | "center" | "bottom">(
    "center",
  );

  // Filters
  const [brightness, setBrightness] = useState(100);
  const [contrast, setContrast] = useState(100);
  const [saturation, setSaturation] = useState(100);

  useEffect(() => {
    const url = URL.createObjectURL(videoFile);
    setVideoUrl(url);
    return () => URL.revokeObjectURL(url);
  }, [videoFile]);

  const togglePlay = () => {
    if (videoRef.current) {
      if (isPlaying) {
        videoRef.current.pause();
      } else {
        void videoRef.current.play();
      }
      setIsPlaying(!isPlaying);
    }
  };

  const handleTimeUpdate = () => {
    if (videoRef.current) {
      setCurrentTime(videoRef.current.currentTime);
    }
  };

  const handleLoadedMetadata = () => {
    if (videoRef.current) {
      setDuration(videoRef.current.duration);
    }
  };

  const formatTime = (time: number) => {
    const minutes = Math.floor(time / 60);
    const seconds = Math.floor(time % 60);
    return `${minutes}:${seconds.toString().padStart(2, "0")}`;
  };

  const editorTabs = [
    { id: "text", label: "Text", icon: Type },
    { id: "music", label: "Music", icon: Music },
    { id: "effects", label: "Effects", icon: Sparkles },
    { id: "filters", label: "Filters", icon: Filter },
  ];

  return (
    <div className="mx-auto max-w-7xl">
      <div className="grid grid-cols-1 gap-6 lg:grid-cols-3">
        {/* Video Preview */}
        <div className="lg:col-span-2">
          <div className="overflow-hidden rounded-2xl bg-black">
            {/* Video Container */}
            <div className="relative mx-auto aspect-[9/16] max-h-[70vh] bg-black">
              {videoUrl && (
                <video
                  ref={videoRef}
                  src={videoUrl}
                  className="h-full w-full object-contain"
                  onTimeUpdate={handleTimeUpdate}
                  onLoadedMetadata={handleLoadedMetadata}
                  muted={isMuted}
                  style={{
                    filter: `brightness(${brightness}%) contrast(${contrast}%) saturate(${saturation}%)`,
                  }}
                />
              )}

              {/* Text Overlay */}
              {textOverlay && (
                <div
                  className={`absolute right-0 left-0 px-4 ${
                    textPosition === "top"
                      ? "top-8"
                      : textPosition === "center"
                        ? "top-1/2 -translate-y-1/2"
                        : "bottom-8"
                  }`}
                >
                  <p
                    className="text-center text-2xl font-bold"
                    style={{
                      color: textColor,
                      textShadow: "2px 2px 4px rgba(0,0,0,0.8)",
                    }}
                  >
                    {textOverlay}
                  </p>
                </div>
              )}

              {/* Play/Pause Overlay */}
              <div
                className="absolute inset-0 flex cursor-pointer items-center justify-center"
                onClick={togglePlay}
              >
                {!isPlaying && (
                  <motion.div
                    initial={{ scale: 0 }}
                    animate={{ scale: 1 }}
                    className="flex h-20 w-20 items-center justify-center rounded-full bg-white/20 backdrop-blur-sm"
                  >
                    <Play className="ml-1 h-10 w-10 text-white" />
                  </motion.div>
                )}
              </div>
            </div>

            {/* Video Controls */}
            <div className="bg-black/50 p-4">
              {/* Progress Bar */}
              <div className="mb-4">
                <input
                  type="range"
                  min="0"
                  max={duration || 0}
                  value={currentTime}
                  onChange={(e) => {
                    if (videoRef.current) {
                      videoRef.current.currentTime = Number(e.target.value);
                    }
                  }}
                  className="h-1 w-full cursor-pointer appearance-none rounded-lg bg-white/20"
                  style={{
                    background: `linear-gradient(to right, #ec4899 0%, #ec4899 ${(currentTime / duration) * 100}%, rgba(255,255,255,0.2) ${(currentTime / duration) * 100}%, rgba(255,255,255,0.2) 100%)`,
                  }}
                />
                <div className="mt-1 flex justify-between text-xs text-gray-400">
                  <span>{formatTime(currentTime)}</span>
                  <span>{formatTime(duration)}</span>
                </div>
              </div>

              {/* Control Buttons */}
              <div className="flex items-center justify-center gap-4">
                <button
                  onClick={togglePlay}
                  className="flex h-12 w-12 items-center justify-center rounded-full bg-white/10 transition-colors hover:bg-white/20"
                >
                  {isPlaying ? (
                    <Pause className="h-5 w-5" />
                  ) : (
                    <Play className="ml-0.5 h-5 w-5" />
                  )}
                </button>
                <button
                  onClick={() => setIsMuted(!isMuted)}
                  className="flex h-12 w-12 items-center justify-center rounded-full bg-white/10 transition-colors hover:bg-white/20"
                >
                  {isMuted ? (
                    <VolumeX className="h-5 w-5" />
                  ) : (
                    <Volume2 className="h-5 w-5" />
                  )}
                </button>
              </div>
            </div>
          </div>
        </div>

        {/* Editor Panel */}
        <div className="lg:col-span-1">
          <div className="rounded-2xl border border-white/10 bg-white/5 p-6">
            <h3 className="mb-6 text-xl font-bold">Customize Video</h3>

            {/* Basic Info */}
            <div className="mb-6 space-y-4">
              <Input
                label="Title"
                placeholder="Give your video a catchy title"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
              />
              <div>
                <label className="mb-2 block text-sm font-medium">
                  Description
                </label>
                <textarea
                  placeholder="Tell viewers about your video..."
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  className="h-24 w-full resize-none rounded-xl border border-white/10 bg-white/5 px-4 py-2 text-white placeholder:text-white/40 focus:ring-2 focus:ring-pink-500 focus:outline-none"
                />
              </div>
            </div>

            {/* Editor Tabs */}
            <div className="mb-6 flex gap-2 overflow-x-auto">
              {editorTabs.map((tab) => {
                const Icon = tab.icon;
                return (
                  <button
                    key={tab.id}
                    onClick={() => setSelectedTab(tab.id as typeof selectedTab)}
                    className={`flex items-center gap-2 rounded-lg px-4 py-2 whitespace-nowrap transition-all ${
                      selectedTab === tab.id
                        ? "bg-gradient-to-r from-pink-500 to-cyan-400 text-white"
                        : "bg-white/5 text-gray-400 hover:bg-white/10"
                    }`}
                  >
                    <Icon className="h-4 w-4" />
                    <span className="text-sm font-medium">{tab.label}</span>
                  </button>
                );
              })}
            </div>

            {/* Tab Content */}
            <div className="space-y-4">
              {selectedTab === "text" && (
                <div className="space-y-4">
                  <Input
                    label="Text Overlay"
                    placeholder="Add text to your video"
                    value={textOverlay}
                    onChange={(e) => setTextOverlay(e.target.value)}
                  />
                  <div>
                    <label className="mb-2 block text-sm font-medium">
                      Text Color
                    </label>
                    <input
                      type="color"
                      value={textColor}
                      onChange={(e) => setTextColor(e.target.value)}
                      className="h-10 w-full cursor-pointer rounded-lg"
                    />
                  </div>
                  <div>
                    <label className="mb-2 block text-sm font-medium">
                      Position
                    </label>
                    <div className="grid grid-cols-3 gap-2">
                      {(["top", "center", "bottom"] as const).map((pos) => (
                        <button
                          key={pos}
                          onClick={() => setTextPosition(pos)}
                          className={`rounded-lg px-4 py-2 capitalize transition-all ${
                            textPosition === pos
                              ? "bg-pink-500 text-white"
                              : "bg-white/5 text-gray-400 hover:bg-white/10"
                          }`}
                        >
                          {pos}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
              )}

              {selectedTab === "music" && (
                <div className="py-8 text-center">
                  <Music className="mx-auto mb-4 h-12 w-12 text-gray-400" />
                  <p className="mb-4 text-gray-400">Add music to your video</p>
                  <button className="rounded-lg bg-white/10 px-6 py-2 transition-colors hover:bg-white/20">
                    Browse Music Library
                  </button>
                </div>
              )}

              {selectedTab === "effects" && (
                <div className="py-8 text-center">
                  <Sparkles className="mx-auto mb-4 h-12 w-12 text-gray-400" />
                  <p className="mb-4 text-gray-400">
                    Apply effects to your video
                  </p>
                  <button className="rounded-lg bg-white/10 px-6 py-2 transition-colors hover:bg-white/20">
                    Browse Effects
                  </button>
                </div>
              )}

              {selectedTab === "filters" && (
                <div className="space-y-4">
                  <div>
                    <label className="mb-2 block text-sm font-medium">
                      Brightness
                    </label>
                    <input
                      type="range"
                      min="0"
                      max="200"
                      value={brightness}
                      onChange={(e) => setBrightness(Number(e.target.value))}
                      className="w-full"
                    />
                    <span className="text-xs text-gray-400">{brightness}%</span>
                  </div>
                  <div>
                    <label className="mb-2 block text-sm font-medium">
                      Contrast
                    </label>
                    <input
                      type="range"
                      min="0"
                      max="200"
                      value={contrast}
                      onChange={(e) => setContrast(Number(e.target.value))}
                      className="w-full"
                    />
                    <span className="text-xs text-gray-400">{contrast}%</span>
                  </div>
                  <div>
                    <label className="mb-2 block text-sm font-medium">
                      Saturation
                    </label>
                    <input
                      type="range"
                      min="0"
                      max="200"
                      value={saturation}
                      onChange={(e) => setSaturation(Number(e.target.value))}
                      className="w-full"
                    />
                    <span className="text-xs text-gray-400">{saturation}%</span>
                  </div>
                </div>
              )}
            </div>

            {/* Action Buttons */}
            <div className="mt-8 flex gap-3">
              <Button
                variant="secondary"
                onClick={onBack}
                className="flex-1"
                disabled={isUploading}
              >
                <ArrowLeft className="mr-2 h-4 w-4" />
                Back
              </Button>
              <Button
                variant="primary"
                onClick={async () => {
                  if (!title.trim()) {
                    toast.error("Please add a title");
                    return;
                  }

                  setIsUploading(true);

                  // Upload video file first
                  const formData = new FormData();
                  formData.append("file", videoFile);

                  try {
                    const uploadResponse = await fetch("/api/upload", {
                      method: "POST",
                      body: formData,
                    });

                    if (!uploadResponse.ok) {
                      throw new Error("Upload failed");
                    }

                    const { filePath } = (await uploadResponse.json()) as {
                      filePath: string;
                    };

                    // Create video record
                    createVideoMutation.mutate({
                      title: title.trim(),
                      description: description.trim() || undefined,
                      filePath,
                      fileSize: videoFile.size,
                    });
                  } catch (error) {
                    toast.error("Failed to upload video");
                    setIsUploading(false);
                  }
                }}
                className="flex-1"
                isLoading={isUploading}
                disabled={isUploading || !title.trim()}
              >
                {isUploading ? "Publishing..." : "Publish"}
                {!isUploading && <ArrowRight className="ml-2 h-4 w-4" />}
              </Button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState, useRef, useCallback } from "react";
import { useInView } from "react-intersection-observer";
import Link from "next/link";
import { motion, AnimatePresence } from "framer-motion";
import { api } from "~/trpc/react";
import VideoCard from "./video-card";
import { ChevronUp, ChevronDown, Loader2 } from "lucide-react";
import { Skeleton } from "~/components/ui/skeleton";

/**
 * A client-side component that displays a TikTok-like vertical-scrolling feed of videos.
 * It fetches video data using a tRPC infinite query and renders individual video cards.
 */
export default function VideoFeed() {
  const [activeVideoIndex, setActiveVideoIndex] = useState(0);
  const { data, fetchNextPage, hasNextPage, isLoading, isError } = api.video.getFeed.useInfiniteQuery(
    {
      limit: 5,
    },
    {
      getNextPageParam: (lastPage) => lastPage.nextCursor,
    }
  );

  const { ref, inView } = useInView({
    threshold: 0.5,
  });

  // Flatten video data from all pages
  const videos = data?.pages.flatMap(page => page.items) ?? [];

  useEffect(() => {
    if (inView && hasNextPage) {
      void fetchNextPage();
    }
  }, [inView, hasNextPage, fetchNextPage]);

  const containerRef = useRef<HTMLDivElement>(null);
  const [isScrolling, setIsScrolling] = useState(false);

  // Handle scroll navigation
  const scrollToVideo = useCallback((index: number) => {
    if (containerRef.current) {
      const videoHeight = window.innerHeight;
      containerRef.current.scrollTo({
        top: index * videoHeight,
        behavior: 'smooth'
      });
    }
  }, []);

  // Handle wheel/scroll events
  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    let scrollTimeout: NodeJS.Timeout;
    const handleScroll = () => {
      setIsScrolling(true);
      clearTimeout(scrollTimeout);

      scrollTimeout = setTimeout(() => {
        setIsScrolling(false);
        const scrollTop = container.scrollTop;
        const videoHeight = window.innerHeight;
        const newIndex = Math.round(scrollTop / videoHeight);

        if (newIndex !== activeVideoIndex && newIndex >= 0 && newIndex < videos.length) {
          setActiveVideoIndex(newIndex);
          scrollToVideo(newIndex);
        }
      }, 150);
    };

    container.addEventListener('scroll', handleScroll);
    return () => {
      container.removeEventListener('scroll', handleScroll);
      clearTimeout(scrollTimeout);
    };
  }, [activeVideoIndex, videos.length, scrollToVideo]);

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'ArrowDown' && activeVideoIndex < videos.length - 1) {
        setActiveVideoIndex(prev => prev + 1);
        scrollToVideo(activeVideoIndex + 1);
      } else if (e.key === 'ArrowUp' && activeVideoIndex > 0) {
        setActiveVideoIndex(prev => prev - 1);
        scrollToVideo(activeVideoIndex - 1);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [activeVideoIndex, videos.length, scrollToVideo]);

  if (isLoading) {
    return (
      <div className="h-screen w-full bg-[#0a0a0a] overflow-hidden flex items-center justify-center relative">
        {/* Animated Mesh Background */}
        <div className="absolute inset-0 opacity-40 pointer-events-none">
           <div className="absolute top-1/4 left-1/4 w-[50vw] h-[50vw] bg-[#7c3aed] rounded-full mix-blend-screen filter blur-[100px] animate-pulse-glow" />
           <div className="absolute bottom-1/4 right-1/4 w-[50vw] h-[50vw] bg-[#ec4899] rounded-full mix-blend-screen filter blur-[100px] animate-pulse-glow" style={{ animationDelay: '1s' }} />
        </div>
        
        <div className="relative z-10 text-center flex flex-col items-center">
           <div className="relative mb-6">
             <div className="absolute inset-0 bg-gradient-to-tr from-[#ec4899] to-[#7c3aed] rounded-full blur-xl opacity-60 animate-pulse-glow" />
             <div className="relative bg-white/5 p-4 rounded-full border border-white/20 backdrop-blur-xl shadow-2xl">
               <Loader2 className="w-8 h-8 text-white animate-spin" />
             </div>
           </div>
           <p className="text-white/80 font-medium tracking-widest uppercase text-xs animate-pulse">Loading Feed</p>
        </div>
      </div>
    );
  }

  if (isError) {
    return (
      <div className="flex flex-col items-center justify-center h-screen bg-black">
        <div className="text-center">
          <p className="text-red-500 text-xl mb-2">Oops! Something went wrong</p>
          <p className="text-white/60 text-sm">Unable to load videos</p>
        </div>
      </div>
    );
  }

  if (videos.length === 0) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-[#0a0a0a]">
        <div className="text-center px-6 max-w-2xl">
          {/* Animated Icon */}
          <motion.div
            initial={{ scale: 0.8, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            transition={{ duration: 0.5 }}
            className="mb-8 inline-block"
          >
            <div className="relative">
              {/* Glow effect */}
              <div className="absolute inset-0 bg-gradient-to-r from-pink-500 to-cyan-400 rounded-3xl blur-3xl opacity-20 animate-pulse-glow" />

              {/* Icon container */}
              <div className="relative bg-gradient-to-br from-pink-500/10 to-cyan-400/10 p-12 rounded-3xl border border-white/10">
                <svg
                  className="w-24 h-24 text-white/80"
                  fill="none"
                  viewBox="0 0 24 24"
                  stroke="currentColor"
                  strokeWidth={1.5}
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z"
                  />
                </svg>
              </div>
            </div>
          </motion.div>

          {/* Text Content */}
          <motion.div
            initial={{ y: 20, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            transition={{ delay: 0.2, duration: 0.5 }}
          >
            <h1 className="text-4xl md:text-5xl font-bold mb-4">
              No videos yet
            </h1>
            <p className="text-lg text-gray-400 mb-10 max-w-md mx-auto">
              Be the first to share your creativity with the world. Upload your first video and start your journey!
            </p>

            {/* CTA Button */}
            <Link href="/upload">
              <motion.button
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
                className="group relative inline-flex items-center gap-3 px-8 py-4 bg-gradient-to-r from-pink-500 to-cyan-400 rounded-xl font-semibold text-white text-lg shadow-2xl shadow-pink-500/20 hover:shadow-pink-500/40 transition-all"
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                </svg>
                <span>Upload Your First Video</span>
                <svg className="w-5 h-5 group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5m0 0l-5 5m5-5H6" />
                </svg>
              </motion.button>
            </Link>
          </motion.div>

          {/* Feature Cards */}
          <motion.div
            initial={{ y: 20, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            transition={{ delay: 0.4, duration: 0.5 }}
            className="mt-16 grid grid-cols-1 md:grid-cols-3 gap-6"
          >
            {[
              {
                icon: (
                  <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" />
                  </svg>
                ),
                title: "Create",
                description: "Share your unique perspective"
              },
              {
                icon: (
                  <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" />
                  </svg>
                ),
                title: "Connect",
                description: "Build your community"
              },
              {
                icon: (
                  <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                  </svg>
                ),
                title: "Inspire",
                description: "Make an impact"
              }
            ].map((feature, i) => (
              <motion.div
                key={feature.title}
                initial={{ y: 20, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                transition={{ delay: 0.5 + i * 0.1, duration: 0.5 }}
