                            <div className="overflow-hidden rounded-2xl border border-white/10">
                                {/* Table header */}
                                <div className="grid grid-cols-[2fr_1fr_1fr_1fr_1fr_auto] gap-4 border-b border-white/10 bg-white/5 px-6 py-3 text-xs font-semibold uppercase tracking-wider text-gray-400">
                                    <span>Video</span>
                                    <span className="text-center">Views</span>
                                    <span className="text-center">Likes</span>
                                    <span className="text-center">Comments</span>
                                    <span className="text-center">Saves</span>
                                    <span />
                                </div>

                                {videoData.videos.map((video, i) => (
                                    <motion.div
                                        key={video.id}
                                        initial={{ opacity: 0, x: -16 }}
                                        animate={{ opacity: 1, x: 0 }}
                                        transition={{ delay: i * 0.04 }}
                                        className="grid grid-cols-[2fr_1fr_1fr_1fr_1fr_auto] items-center gap-4 border-b border-white/5 px-6 py-4 transition-colors hover:bg-white/5"
                                    >
                                        {/* Thumbnail + title */}
                                        <div className="flex items-center gap-3">
                                            <div className="h-14 w-10 flex-shrink-0 overflow-hidden rounded-lg bg-white/10">
                                                {video.thumbnailUrl ? (
                                                    // eslint-disable-next-line @next/next/no-img-element
                                                    <img
                                                        src={video.thumbnailUrl}
                                                        alt={video.title ?? "Video"}
                                                        className="h-full w-full object-cover"
                                                    />
                                                ) : (
                                                    <video
                                                        src={video.filePath}
                                                        className="h-full w-full object-cover"
                                                        muted
                                                    />
                                                )}
                                            </div>
                                            <div className="min-w-0">
                                                <p className="truncate text-sm font-medium">
                                                    {video.title ?? "Untitled"}
                                                </p>
                                                <p className="text-xs text-gray-400">
                                                    {formatDistanceToNow(new Date(video.createdAt), { addSuffix: true })}
                                                </p>
                                            </div>
                                        </div>

                                        <span className="text-center text-sm font-semibold">
                                            {formatNumber(video._count.views)}
                                        </span>
                                        <span className="text-center text-sm font-semibold text-[#FE2C55]">
                                            {formatNumber(video._count.likes)}
                                        </span>
                                        <span className="text-center text-sm font-semibold text-cyan-400">
                                            {formatNumber(video._count.comments)}
                                        </span>
                                        <span className="text-center text-sm font-semibold text-amber-400">
                                            {formatNumber(video._count.bookmarks)}
                                        </span>

                                        {/* Actions */}
                                        <div className="flex items-center gap-2">
                                            <button
                                                onClick={() => deleteVideoMutation?.mutate?.({ videoId: video.id })}
                                                className="rounded-lg p-2 text-gray-500 transition-colors hover:bg-red-500/10 hover:text-red-400"
                                                title="Delete video"
                                            >
                                                <Trash2 className="h-4 w-4" />
                                            </button>
                                            <MoreVertical className="h-4 w-4 text-gray-500" />
                                        </div>
                                    </motion.div>
                                ))}
                            </div>
                        )}
                    </div>
                )}
            </div>
        </main>
    );
}

"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Upload, Video, Edit3, Music, Type, Sparkles, Check } from "lucide-react";
import VideoUploader from "~/app/_components/video-uploader";
import VideoEditor from "~/app/_components/video-editor";

export default function UploadPage() {
  const [step, setStep] = useState<'upload' | 'edit' | 'publish'>('upload');
  const [videoFile, setVideoFile] = useState<File | null>(null);

  const steps = [
    { id: 'upload', label: 'Upload', icon: Upload },
    { id: 'edit', label: 'Edit', icon: Edit3 },
    { id: 'publish', label: 'Publish', icon: Check },
  ];

  return (
    <main className="min-h-screen bg-[#0a0a0a] text-white">
      <div className="max-w-7xl mx-auto px-4 py-8">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold mb-2">Create New Video</h1>
          <p className="text-gray-400">Upload and customize your video before sharing</p>
        </div>

        {/* Progress Steps */}
        <div className="mb-12">
          <div className="flex items-center justify-center gap-4">
            {steps.map((s, index) => {
              const Icon = s.icon;
              const isActive = s.id === step;
              const isCompleted = steps.findIndex(st => st.id === step) > index;
              
              return (
                <div key={s.id} className="flex items-center">
                  <motion.div
                    whileHover={{ scale: 1.05 }}
                    className="flex flex-col items-center gap-2"
                  >
                    <div
                      className={`w-12 h-12 rounded-full flex items-center justify-center transition-all ${
                        isActive
                          ? 'bg-gradient-to-r from-pink-500 to-cyan-400 text-white'
                          : isCompleted
                          ? 'bg-green-500 text-white'
                          : 'bg-white/10 text-gray-400'
                      }`}
                    >
                      <Icon className="w-5 h-5" />
                    </div>
                    <span
                      className={`text-sm font-medium ${
                        isActive ? 'text-white' : 'text-gray-400'
                      }`}
                    >
                      {s.label}
                    </span>
                  </motion.div>
                  
                  {index < steps.length - 1 && (
                    <div className="w-24 h-0.5 mx-4 bg-white/10">
                      <div
                        className={`h-full transition-all ${
                          isCompleted ? 'bg-green-500 w-full' : 'w-0'
                        }`}
                      />
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>

        {/* Content */}
        <AnimatePresence mode="wait">
          {step === 'upload' && (
            <motion.div
              key="upload"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
            >
              <VideoUploader
                onVideoSelect={(file) => {
                  setVideoFile(file);
                  setStep('edit');
                }}
              />
            </motion.div>
          )}

          {step === 'edit' && videoFile && (
            <motion.div
              key="edit"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
            >
              <VideoEditor
                videoFile={videoFile}
                onBack={() => setStep('upload')}
                onNext={() => setStep('publish')}
              />
            </motion.div>
          )}

          {step === 'publish' && (
            <motion.div
              key="publish"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
              className="text-center py-12"
            >
              <div className="w-20 h-20 mx-auto mb-6 rounded-full bg-green-500/20 flex items-center justify-center">
                <Check className="w-10 h-10 text-green-500" />
              </div>
              <h2 className="text-2xl font-bold mb-2">Video Published!</h2>
              <p className="text-gray-400 mb-8">Your video is now live and ready to be discovered</p>
              <button
                onClick={() => {
                  setStep('upload');
                  setVideoFile(null);
                }}
                className="px-6 py-3 bg-gradient-to-r from-pink-500 to-cyan-400 rounded-xl font-semibold"
              >
                Upload Another Video
              </button>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </main>
  );
}

import * as React from "react";
import { cn } from "~/lib/utils";

interface AvatarProps extends React.HTMLAttributes<HTMLDivElement> {
  src?: string;
  alt?: string;
  fallback?: string;
  size?: "sm" | "md" | "lg" | "xl";
}

const sizeClasses = {
  sm: "h-8 w-8 text-xs",
  md: "h-10 w-10 text-sm",
  lg: "h-12 w-12 text-base",
  xl: "h-16 w-16 text-lg",
};

export function Avatar({ 
  src, 
  alt, 
  fallback, 
  size = "md", 
  className,
  ...props 
}: AvatarProps) {
  const [imageError, setImageError] = React.useState(false);

  return (
    <div
      className={cn(
        "relative inline-flex items-center justify-center overflow-hidden rounded-full bg-gradient-to-br from-pink-500 via-purple-500 to-indigo-500 p-[2px]",
        sizeClasses[size],
        className
      )}
      {...props}
    >
      <div className="flex h-full w-full items-center justify-center rounded-full bg-black">
        {src && !imageError ? (
          <img
            src={src}
            alt={alt ?? "Avatar"}
            className="h-full w-full rounded-full object-cover"
            onError={() => setImageError(true)}
          />
        ) : (
          <span className="font-bold text-white">
            {fallback ?? "?"}
          </span>
        )}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useRef, useState, useCallback } from "react";
import { api } from "~/trpc/react";
import { getPusherClient, conversationChannel, PUSHER_EVENTS } from "~/lib/pusher";

// Note: Replace with production ICE servers (e.g., Twilio/Xirsys) for broader reach
const ICE_SERVERS = {
    iceServers: [
        { urls: "stun:stun.l.google.com:19302" },
        { urls: "stun:stun1.l.google.com:19302" },
    ],
};

interface UseWebRTCProps {
    conversationId: string;
    userId: string; // The current user's ID
    isVideo?: boolean; // false for audio-only
}

export function useWebRTC({ conversationId, userId, isVideo = true }: UseWebRTCProps) {
    const [localStream, setLocalStream] = useState<MediaStream | null>(null);
    const [remoteStream, setRemoteStream] = useState<MediaStream | null>(null);
    const [isCallActive, setIsCallActive] = useState(false);
    const [callStatus, setCallStatus] = useState<"idle" | "calling" | "ringing" | "connected">("idle");

    const peerConnection = useRef<RTCPeerConnection | null>(null);
    const signalMutation = api.webrtc.signal.useMutation();

    // Create or retrieve PeerConnection
    const getPeerConnection = useCallback(() => {
        if (!peerConnection.current) {
            peerConnection.current = new RTCPeerConnection(ICE_SERVERS);

            // Add local stream tracks to connection
            if (localStream) {
                localStream.getTracks().forEach((track) => {
                    peerConnection.current?.addTrack(track, localStream);
                });
            }

            // Handle incoming remote stream
            peerConnection.current.ontrack = (event) => {
                setRemoteStream(event.streams[0] ?? null);
            };

            // Handle ICE candidates negotiation
            peerConnection.current.onicecandidate = (event) => {
                if (event.candidate) {
                    signalMutation.mutate({
                        conversationId,
                        signalType: "ice-candidate",
                        candidate: event.candidate.candidate,
                        sdpMid: event.candidate.sdpMid,
                        sdpMLineIndex: event.candidate.sdpMLineIndex,
                    });
                }
            };

            peerConnection.current.onconnectionstatechange = () => {
                if (peerConnection.current?.connectionState === "connected") {
                    setCallStatus("connected");
                } else if (
                    peerConnection.current?.connectionState === "failed" ||
                    peerConnection.current?.connectionState === "disconnected" ||
                    peerConnection.current?.connectionState === "closed"
                ) {
                    endCall();
                }
            };
        }
        return peerConnection.current;
    }, [conversationId, localStream, signalMutation]);

    // Handle incoming signaling events via Pusher
    useEffect(() => {
        if (!conversationId) return;

        const pusher = getPusherClient();
        const channel = pusher.subscribe(conversationChannel(conversationId));

        channel.bind(PUSHER_EVENTS.CALL_SIGNALING, async (data: any) => {
            // Ignore our own signals
            if (data.senderId === userId) return;

            if (data.signalType === "end-call") {
                endCall(false); // End call remotely
                return;
            }

            const pc = getPeerConnection();

            try {
                if (data.signalType === "offer") {
                    setCallStatus("ringing");
                    await pc.setRemoteDescription(new RTCSessionDescription({ type: "offer", sdp: data.sdp }));

                    // Auto-answer logic (or you can separate this to wait for user interaction)
                    const answer = await pc.createAnswer();
                    await pc.setLocalDescription(answer);

                    signalMutation.mutate({
                        conversationId,
                        signalType: "answer",
                        sdp: answer.sdp,
                    });
                } else if (data.signalType === "answer") {
                    await pc.setRemoteDescription(new RTCSessionDescription({ type: "answer", sdp: data.sdp }));
                } else if (data.signalType === "ice-candidate") {
                    await pc.addIceCandidate(
                        new RTCIceCandidate({
                            candidate: data.candidate,
                            sdpMid: data.sdpMid,
                            sdpMLineIndex: data.sdpMLineIndex,
                        })
                    );
                }
            } catch (err) {
                console.error("WebRTC Error:", err);
            }
        });

        return () => {
            pusher.unsubscribe(conversationChannel(conversationId));
            channel.unbind(PUSHER_EVENTS.CALL_SIGNALING);
        };
    }, [conversationId, userId, getPeerConnection, signalMutation]);

    const startMedia = async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({
                video: isVideo,
                audio: true,
            });
            setLocalStream(stream);

            // If PC already exists, add tracks dynamically
            if (peerConnection.current) {
                stream.getTracks().forEach((track) => {
                    peerConnection.current?.addTrack(track, stream);
                });
            }
        } catch (err) {
            console.error("Error accessing media devices.", err);
        }
    };

    const startCall = async () => {
        setIsCallActive(true);
        setCallStatus("calling");

        const pc = getPeerConnection();
        const offer = await pc.createOffer();
        await pc.setLocalDescription(offer);

        signalMutation.mutate({
            conversationId,
            signalType: "offer",
            sdp: offer.sdp,
        });
    };

    const endCall = (broadcast = true) => {
        if (broadcast) {
            signalMutation.mutate({
                conversationId,
                signalType: "end-call",
            });
        }

        if (peerConnection.current) {
            peerConnection.current.close();
            peerConnection.current = null;
        }

        if (localStream) {
            localStream.getTracks().forEach((track) => track.stop());
            setLocalStream(null);
        }

        setRemoteStream(null);
        setIsCallActive(false);
        setCallStatus("idle");
    };

    return {
        localStream,
        remoteStream,
        isCallActive,
        callStatus,
        startMedia,
        startCall,
        endCall,
        setCallStatus,
    };
}

import { z } from "zod";
import { ulid } from "ulidx";
import { tickClock, type VectorClock } from "./vector-clock";

export const eventTypeSchema = z.enum([
  "message:send",
  "message:read",
  "message:delete",
  "conversation:typing"
]);

export const eventEnvelopeSchema = z.object({
  id: z.string(), // ULID
  type: eventTypeSchema,
  conversationId: z.string().min(1),
  senderId: z.string().min(1),
  timestamp: z.number().int().nonnegative(),
  vectorClock: z.record(z.string(), z.number().int().nonnegative()),
  payload: z.any(),
});

export type EventType = z.infer<typeof eventTypeSchema>;
export type EventEnvelope<T = any> = Omit<z.infer<typeof eventEnvelopeSchema>, 'payload'> & { payload: T };

export const parseEventEnvelope = (value: unknown) =>
  eventEnvelopeSchema.parse(value) as EventEnvelope;

/**
 * Event Factory
 * Creates a locally sequenced event envelope ready to be broadcast/persisted.
 */
export function createEvent<T>(
  type: EventType,
  payload: T,
  clock: VectorClock,
  senderId: string,
  conversationId: string
): EventEnvelope<T> {
  const updatedClock = tickClock(clock, senderId);

  return {
    id: ulid(),
    type,
    payload,
    vectorClock: updatedClock,
    timestamp: Date.now(),
    senderId,
    conversationId,
  };
}

/**
 * Event Types and Envelope Schema for Aurora
 * 
 * In this architecture, we don't just "create a message" in a table.
 * Instead, we create a "message:send" EventEnvelope. The message state
 * is simply a projection of all events in the conversation log.
 */

// Global string-map for tracking causal event order across nodes
export type VectorClock = Record<string, number>;

// All allowed event types in the system
export type EventType =
    | "message:send"
    | "message:read"
    | "message:delete"
    // Future types (video likes, chat typing, etc)
    | "conversation:typing";

export interface EventEnvelope<T = any> {
    id: string;             // ULID ΓÇö monotonic, sortable, globally unique ID
    type: EventType;        // Discriminant type
    payload: T;             // Event-specific data payload
    vectorClock: VectorClock; // The sender's clock state at time of event creation
    timestamp: number;      // Client-side JS timestamp (Unix epoch ms)
    senderId: string;       // User ID who created this event
    conversationId: string; // The primary partition/topic channel
}

// Payload specifically for a new chat message
export interface MessageSendPayload {
    messageId: string; // Unique ID for the message itself (UUID/CUID)
    content: string;
}

// Payload for acknowledging read receipts up to an event
export interface MessageReadPayload {
    lastReadEventId: string; // The highest ULID read by the user
}

// Payload for deleting a specific message
export interface MessageDeletePayload {
    messageId: string;
}

/**
 * Content Moderation Utilities
 * Similar to Instagram/TikTok content filtering
 */

// Comprehensive list of banned keywords
const BANNED_KEYWORDS = [
  // Explicit content
  "porn",
  "xxx",
  "nsfw",
  "explicit",
  "adult",
  "nude",
  "naked",
  "sex",
  "sexual",
  
  // Violence
  "gore",
  "blood",
  "violence",
  "kill",
  "murder",
  "weapon",
  
  // Hate speech
  "hate",
  "racist",
  "discrimination",
  
  // Drugs
  "drug",
  "cocaine",
  "heroin",
  "meth",
  
  // Add more as needed
];

// Suspicious patterns
const SUSPICIOUS_PATTERNS = [
  /\b(18\+|21\+|adult\s*only)\b/i,
  /\b(click\s*here|free\s*download)\b/i,
  /\b(hack|crack|pirate)\b/i,
];

/**
 * Check if text contains banned content
 */
export function containsBannedContent(text: string): boolean {
  // Use word-boundary regex to avoid false positives (e.g. "hackathon", "blood orange", "adult education")
  const hasBannedKeyword = BANNED_KEYWORDS.some((keyword) =>
    new RegExp(`\\b${keyword}\\b`, "i").test(text)
  );

  if (hasBannedKeyword) return true;

  // Check suspicious patterns
  const hasSuspiciousPattern = SUSPICIOUS_PATTERNS.some((pattern) =>
    pattern.test(text)
  );

  return hasSuspiciousPattern;
}

/**
 * Check if video metadata is appropriate
 */
export function moderateVideoMetadata(data: {
  title?: string;
  description?: string;
  filename?: string;
}): { allowed: boolean; reason?: string } {
  const { title, description, filename } = data;
  
  // Check title
  if (title && containsBannedContent(title)) {
    return {
      allowed: false,
      reason: "Title contains inappropriate content",
    };
  }
  
  // Check description
  if (description && containsBannedContent(description)) {
    return {
      allowed: false,
      reason: "Description contains inappropriate content",
    };
  }
  
  // Check filename
  if (filename && containsBannedContent(filename)) {
    return {
      allowed: false,
      reason: "Filename contains inappropriate content",
    };
  }
  
  return { allowed: true };
}

/**
 * Get content warning level
 */
export function getContentWarningLevel(text: string): "safe" | "warning" | "blocked" {
  if (containsBannedContent(text)) {
    return "blocked";
  }

  // Use word-boundary regex to avoid false positives on warning-level words
  const warningKeywords = ["violence", "blood", "scary"];
  const hasWarning = warningKeywords.some((keyword) =>
    new RegExp(`\\b${keyword}\\b`, "i").test(text)
  );

  if (hasWarning) {
    return "warning";
  }

  return "safe";
}

/**
 * Sanitize text by removing suspicious content
 */
export function sanitizeText(text: string): string {
  let sanitized = text;
  
  // Remove URLs
  sanitized = sanitized.replace(/https?:\/\/[^\s]+/g, "[link removed]");
  
  // Remove email addresses
  sanitized = sanitized.replace(/[\w.-]+@[\w.-]+\.\w+/g, "[email removed]");
  
  // Remove phone numbers
  sanitized = sanitized.replace(/\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g, "[phone removed]");
  
  return sanitized;
}

/**
 * Check if user is spamming
 */
export function isSpamming(
  recentUploads: Date[],
  maxUploadsPerHour: number = 10
): boolean {
  const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000);
  const recentCount = recentUploads.filter((date) => date > oneHourAgo).length;
  return recentCount >= maxUploadsPerHour;
}

/**
 * Report content for manual review
 */
export interface ContentReport {
  contentId: string;
  contentType: "video" | "comment" | "message";
  reason: string;
  reportedBy: string;
  timestamp: Date;
}

export function createContentReport(
  contentId: string,
  contentType: "video" | "comment" | "message",
  reason: string,
  reportedBy: string
): ContentReport {
  return {
    contentId,
    contentType,
    reason,
    reportedBy,
    timestamp: new Date(),
  };
}

