import { z } from "zod";
import { TRPCError } from "@trpc/server";
import { MessageStatus } from "@prisma/client";
import { createTRPCRouter, protectedProcedure } from "~/server/api/trpc";
import { checkRateLimit } from "~/lib/rate-limit";

export const messageRouter = createTRPCRouter({
  /**
   * Get all conversations for the current user
   */
  getConversations: protectedProcedure.query(async ({ ctx }) => {
    const userId = ctx.session.user.id;

    const conversations = await ctx.db.conversation.findMany({
      where: {
        participants: {
          some: {
            userId,
          },
        },
      },
      include: {
        participants: {
          include: {
            user: {
              select: {
                id: true,
                name: true,
                username: true,
                image: true,
              },
            },
          },
        },
        messages: {
          orderBy: {
            createdAt: "desc",
          },
          take: 1,
        },
      },
      orderBy: {
        updatedAt: "desc",
      },
    });

    return conversations.map((conv) => ({
      ...conv,
      otherParticipant: conv.participants.find((p) => p.userId !== userId)?.user,
      lastMessage: conv.messages[0],
    }));
  }),

  /**
   * Get messages for a specific conversation
   */
  getMessages: protectedProcedure
    .input(
      z.object({
        conversationId: z.string(),
        cursor: z.string().optional(),
        limit: z.number().min(1).max(100).default(30),
      })
    )
    .query(async ({ ctx, input }) => {
      const userId = ctx.session.user.id;
      const { conversationId, cursor, limit } = input;

      // Security: verify the caller is a participant in this conversation
      const participant = await ctx.db.conversationParticipant.findFirst({
        where: {
          conversationId,
          userId,
        },
      });

      if (!participant) {
        throw new TRPCError({
          code: "FORBIDDEN",
          message: "You are not a participant in this conversation.",
        });
      }

      const messages = await ctx.db.message.findMany({
        where: { conversationId },
        include: {
          sender: {
            select: {
              id: true,
              name: true,
              username: true,
              image: true,
            },
          },
        },
        orderBy: { createdAt: "asc" },
        take: limit + 1,
        ...(cursor ? { cursor: { id: cursor }, skip: 1 } : {}),
      });

      let nextCursor: string | undefined;
      if (messages.length > limit) {
        const nextItem = messages.pop();
        nextCursor = nextItem?.id;
      }

      return { items: messages, nextCursor };
    }),

  /**
   * Send a message
   */
  sendMessage: protectedProcedure
    .input(
      z.object({
        conversationId: z.string().optional(),
        recipientId: z.string(),
        content: z.string().min(1).max(2000),
      })
    )
    .mutation(async ({ ctx, input }) => {
      const senderId = ctx.session.user.id;

      // Rate limit: 30 messages per minute per user
      checkRateLimit(`sendMessage:${senderId}`, 30, 60_000);

      const { conversationId, recipientId, content } = input;

      let convId = conversationId;

      // If no conversation ID, find or create one atomically inside a transaction
      if (!convId) {
        convId = await ctx.db.$transaction(async (tx) => {
          const existingConv = await tx.conversation.findFirst({
            where: {
              AND: [
                {
                  participants: {
                    some: {
                      userId: senderId,
                    },
                  },
                },
                {
                  participants: {
                    some: {
                      userId: recipientId,
                    },
                  },
                },
              ],
            },
          });

          if (existingConv) {
            return existingConv.id;
          }

          // Create new conversation
          const newConv = await tx.conversation.create({
            data: {
              participants: {
                create: [
                  { userId: senderId },
                  { userId: recipientId },
                ],
              },
            },
          });
          return newConv.id;
        });
      }

      // Create the message
      const message = await ctx.db.message.create({
        data: {
          content,
          senderId,
          conversationId: convId,
        },
        include: {
          sender: {
            select: {
              id: true,
              name: true,
              username: true,
              image: true,
            },
          },
        },
      });

      // Update conversation timestamp
      await ctx.db.conversation.update({
        where: { id: convId },
        data: { updatedAt: new Date() },
      });

      return {
        ...message,
        conversationId: convId,
      };
    }),

  /**
   * Mark conversation as read
   */
  markAsRead: protectedProcedure
    .input(z.object({ conversationId: z.string() }))
    .mutation(async ({ ctx, input }) => {
      const userId = ctx.session.user.id;

      // Update conversation participant
      await ctx.db.conversationParticipant.updateMany({
        where: {
          conversationId: input.conversationId,
          userId,
        },
        data: {
          lastReadAt: new Date(),
        },
      });

      // Mark all messages in conversation as read
      await ctx.db.message.updateMany({
        where: {
          conversationId: input.conversationId,
          senderId: { not: userId }, // Only mark others' messages
          status: { not: MessageStatus.read },
        },
        data: {
          status: MessageStatus.read,
          readAt: new Date(),
        },
      });

      return { success: true };
    }),

  /**
   * Mark messages as delivered when user opens conversation
   */
  markAsDelivered: protectedProcedure
    .input(z.object({ conversationId: z.string() }))
    .mutation(async ({ ctx, input }) => {
      const userId = ctx.session.user.id;

      await ctx.db.message.updateMany({
        where: {
          conversationId: input.conversationId,
          senderId: { not: userId },
          status: MessageStatus.sent,
        },
        data: {
          status: MessageStatus.delivered,
        },
      });

      return { success: true };
    }),
});

import { PrismaAdapter } from "@auth/prisma-adapter";
import { type DefaultSession, type NextAuthConfig } from "next-auth";
import CredentialsProvider from "next-auth/providers/credentials";
import GoogleProvider from "next-auth/providers/google";
import FacebookProvider from "next-auth/providers/facebook";
import bcrypt from "bcryptjs";
import { z } from "zod";

import { db } from "~/server/db";

/**
 * Module augmentation for `next-auth` types. Allows us to add custom properties to the `session`
 * object and keep type safety.
 *
 * @see https://next-auth.js.org/getting-started/typescript#module-augmentation
 */
declare module "next-auth" {
  interface Session extends DefaultSession {
    user: {
      id: string;
      username?: string;
      bio?: string;
    } & DefaultSession["user"];
  }

  interface User {
    username?: string;
    bio?: string;
  }
}

/**
 * Options for NextAuth.js used to configure adapters, providers, callbacks, etc.
 *
 * @see https://next-auth.js.org/configuration/options
 */
const loginSchema = z.object({
  email: z.string().email().transform((v) => v.trim().toLowerCase()),
  password: z.string().min(6),
});

export const authConfig = {
  providers: [
    GoogleProvider({
      clientId: process.env.GOOGLE_CLIENT_ID ?? "",
      clientSecret: process.env.GOOGLE_CLIENT_SECRET ?? "",
      allowDangerousEmailAccountLinking: true,
    }),
    FacebookProvider({
      clientId: process.env.FACEBOOK_CLIENT_ID ?? "",
      clientSecret: process.env.FACEBOOK_CLIENT_SECRET ?? "",
      allowDangerousEmailAccountLinking: true,
    }),
    CredentialsProvider({
      name: "credentials",
      credentials: {
        email: { label: "Email", type: "email" },
        password: { label: "Password", type: "password" },
      },
      async authorize(credentials) {
        try {
          const { email, password } = loginSchema.parse(credentials);

          const user = await db.user.findUnique({
            where: { email },
          });

          if (!user?.password) {
            return null;
          }

          const isValidPassword = await bcrypt.compare(password, user.password);

          if (!isValidPassword) {
            return null;
          }

          return {
            id: user.id,
            email: user.email ?? undefined,
            name: user.name ?? undefined,
            username: user.username ?? undefined,
          };
        } catch {
          return null;
        }
      },
    }),
  ],
  adapter: PrismaAdapter(db),
  session: {
    strategy: "jwt",
  },
  callbacks: {
    jwt: ({ token, user, trigger, session }) => {
      if (user) {
        token.id = user.id;
        token.username = user.username ?? undefined;
        token.bio = user.bio ?? undefined;
      }
      // Handle session updates
      if (trigger === "update" && session) {
        token.username = session.user?.username ?? token.username;
        token.bio = session.user?.bio ?? token.bio;
      }
      return token;
    },
    session: ({ session, token }) => ({
      ...session,
      user: {
        ...session.user,
        id: token.id as string,
        username: token.username as string | undefined,
        bio: token.bio as string | undefined,
      },
    }),
  },
  pages: {
    signIn: "/auth/signin",
  },
} satisfies NextAuthConfig;

import { WebSocketServer, WebSocket } from "ws";
import { type EventEnvelope } from "../../lib/aurora/types";

// Keep track of which connection is listening to which conversations
// Map<conversationId, Set<WebSocket>>
const subscriptions = new Map<string, Set<WebSocket>>();

const port = Number(process.env.WS_PORT || 3001);

export function createAuroraGateway() {
    const wss = new WebSocketServer({ port });

    wss.on("connection", (ws, req) => {
        console.log("[Aurora WS] Client connected", req.url);

        // Track which conversations this specific WS connection is subscribed to
        const clientSubscriptions = new Set<string>();

        ws.on("message", (messageData) => {
            try {
                const data = JSON.parse(messageData.toString());

                // 1. Handle Subscriptions
                if (data.type === "subscribe" && data.conversationId) {
                    const { conversationId } = data;

                    if (!subscriptions.has(conversationId)) {
                        subscriptions.set(conversationId, new Set());
                    }
                    subscriptions.get(conversationId)!.add(ws);
                    clientSubscriptions.add(conversationId);

                    console.log(`[Aurora WS] Client subscribed to ${conversationId}`);
                    return;
                }

                // 2. Handle Event Envelopes
                if (data.type === "event" && data.envelope) {
                    const envelope = data.envelope as EventEnvelope;
                    const { conversationId } = envelope;

                    // TODO: Persist the envelope to the database via Prisma here
                    // For now, we just act as a Pub/Sub router

                    // Broadcast to everyone else in the conversation
                    const subscribers = subscriptions.get(conversationId);
                    if (subscribers) {
                        const broadcastPayload = JSON.stringify({
                            type: "event",
                            envelope
                        });

                        for (const client of subscribers) {
                            // Don't echo back to the sender
                            if (client !== ws && client.readyState === WebSocket.OPEN) {
                                client.send(broadcastPayload);
                            }
                        }
                    }
                }
            } catch (err) {
                console.error("[Aurora WS] Error parsing message", err);
            }
        });

        ws.on("close", () => {
            console.log("[Aurora WS] Client disconnected");
            // Clean up subscriptions
            for (const conversationId of clientSubscriptions) {
                const subs = subscriptions.get(conversationId);
                if (subs) {
                    subs.delete(ws);
                    if (subs.size === 0) {
                        subscriptions.delete(conversationId);
                    }
                }
            }
        });
    });

    console.log(`> Aurora WS Gateway attached at ws://localhost:${port}`);
    return wss;
}

// Automatically start if called directly
if (require.main === module) {
    createAuroraGateway();
}

import { WebSocketServer, type WebSocket, type RawData } from "ws";
import { PrismaClient } from "@prisma/client";
import PusherServer from "pusher";

const port = 3001;
const db = new PrismaClient();
const wss = new WebSocketServer({ port });

// Pusher server instance for relaying events to clients
const pusher = new PusherServer({
  appId: process.env.PUSHER_APP_ID!,
  key: process.env.NEXT_PUBLIC_PUSHER_KEY!,
  secret: process.env.PUSHER_SECRET!,
  cluster: process.env.NEXT_PUBLIC_PUSHER_CLUSTER!,
  useTLS: true,
});

console.log(`> Aurora WS attached at ws://localhost:${port}`);

wss.on("connection", (ws: WebSocket) => {
  console.log("WS client connected");

  ws.on("message", async (raw: RawData) => {
    try {
      const event = JSON.parse(raw.toString()) as {
        type: string;
        payload: Record<string, unknown>;
        senderId: string;
        conversationId: string;
        vectorClock?: Record<string, number>;
        id?: string;
      };

      // Persist the event to the MessageEvent log
      const persisted = await db.messageEvent.create({
        data: {
          id: event.id ?? crypto.randomUUID(),
          type: event.type,
          payload: event.payload as any,
          vectorClock: event.vectorClock ?? {},
          timestamp: BigInt(Date.now()),
          senderId: event.senderId,
          conversationId: event.conversationId,
        },
      });

      // Relay to Pusher so browser clients receive it in real-time
      await pusher.trigger(
        `private-conversation-${event.conversationId}`,
        event.type,
        { ...event.payload, eventId: persisted.id }
      );

      console.log(`[WS] Relayed event ${event.type} for conversation ${event.conversationId}`);
    } catch (e) {
      console.error("[WS] Error processing message:", e);
    }
  });

  ws.on("close", () => console.log("WS client disconnected"));
  ws.on("error", (err: Error) => console.error("[WS] Socket error:", err));
});
